import{_ as e,o as a,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"Onboarding and Config Protocol","description":"","frontmatter":{"summary":"RPC protocol notes for onboarding wizard and config schema","read_when":"Changing onboarding wizard steps or config schema endpoints","title":"Onboarding and Config Protocol"},"headers":[],"relativePath":"experiments/onboarding-config-protocol.md","filePath":"experiments/onboarding-config-protocol.md","lastUpdated":1771906665000}'),s={name:"experiments/onboarding-config-protocol.md"};function r(d,o,t,c,l,p){return a(),i("div",null,[...o[0]||(o[0]=[n('<h1 id="onboarding-config-protocol" tabindex="-1"><a class="header-anchor" href="#onboarding-config-protocol">#</a> Onboarding + Config Protocol</h1><p>Purpose: shared onboarding + config surfaces across CLI, macOS app, and Web UI.</p><h2 id="components" tabindex="-1"><a class="header-anchor" href="#components">#</a> Components</h2><ul><li>Wizard engine (shared session + prompts + onboarding state).</li><li>CLI onboarding uses the same wizard flow as the UI clients.</li><li>Gateway RPC exposes wizard + config schema endpoints.</li><li>macOS onboarding uses the wizard step model.</li><li>Web UI renders config forms from JSON Schema + UI hints.</li></ul><h2 id="gateway-rpc" tabindex="-1"><a class="header-anchor" href="#gateway-rpc">#</a> Gateway RPC</h2><ul><li><code>wizard.start</code> params: <code>{ mode?: &quot;local&quot;|&quot;remote&quot;, workspace?: string }</code></li><li><code>wizard.next</code> params: <code>{ sessionId, answer?: { stepId, value? } }</code></li><li><code>wizard.cancel</code> params: <code>{ sessionId }</code></li><li><code>wizard.status</code> params: <code>{ sessionId }</code></li><li><code>config.schema</code> params: <code>{}</code></li></ul><p>Responses (shape)</p><ul><li>Wizard: <code>{ sessionId, done, step?, status?, error? }</code></li><li>Config schema: <code>{ schema, uiHints, version, generatedAt }</code></li></ul><h2 id="ui-hints" tabindex="-1"><a class="header-anchor" href="#ui-hints">#</a> UI Hints</h2><ul><li><code>uiHints</code> keyed by path; optional metadata (label/help/group/order/advanced/sensitive/placeholder).</li><li>Sensitive fields render as password inputs; no redaction layer.</li><li>Unsupported schema nodes fall back to the raw JSON editor.</li></ul><h2 id="notes" tabindex="-1"><a class="header-anchor" href="#notes">#</a> Notes</h2><ul><li>This doc is the single place to track protocol refactors for onboarding/config.</li></ul>',12)])])}const m=e(s,[["render",r]]);export{g as __pageData,m as default};
